"""Long prayer/liturgy translations for build_prayers_liturgy.py"""


def add_long_texts(add, T):  # noqa: ANN001
    # --- Ps 137 (Tachanun days) ---
    EN137 = """On ordinary weekdays when Tachanun is said, say:

By the rivers of Babylon, there we sat and wept when we remembered Zion. Upon the willows in its midst we hung our harps. For there our captors asked us for words of song, and our tormentors [asked of us] mirth: 'Sing for us from Zion's song.' How shall we sing the Lord's song on alien soil? If I forget you, O Jerusalem, let my right hand forget its skill. Let my tongue cleave to my palate if I do not remember you, if I do not bring up Jerusalem at the beginning of my joy. Remember, O Lord, against the Edomites the day of Jerusalem, who said, 'Raze it, raze it to its very foundation!' O daughter of Babylon, who is destined to be plundered, praiseworthy is he who repays you your recompense for what you did to us. Praiseworthy is he who will take and dash your infants against the rock."""

    ES137 = """En días laborables ordinarios, cuando se dice Tachanun, se recita:

Junto a los ríos de Babilonia, allí nos sentamos y lloramos al recordar a Sión. Sobre los sauces en medio de ella colgamos nuestras arpas. Porque allí nuestros captores nos pedían palabras de canto, y nuestros opresores alegría: «Cántennos de las canciones de Sión». ¿Cómo cantaremos el canto de Hashem en tierra extraña? Si me olvidare de ti, Jerusalén, que se olvide mi diestra. Que se pegue mi lengua a mi paladar si no me acordare de ti, si no elevare a Jerusalén sobre el principio de mi alegría. Acuérdate, Hashem, del día de Jerusalén contra los hijos de Edom, que decían: «Arrasad, arrasad hasta sus cimientos». Hija de Babilonia, la devastada, bienaventurado el que te retribuya el pago que nos diste. Bienaventurado el que tome y estrelle contra la roca a tus pequeños."""

    FR137 = """Les jours ordinaires de semaine, lorsque l'on récite Tachanoun, on dit :

Aux rivières de Babylone, là nous nous sommes assis et avons pleuré en nous souvenant de Sion. Sur les saules au milieu d'elle nous avons suspendu nos harpes. Car là nos capteurs nous demandaient des paroles de chant, et nos oppresseurs de la joie : « Chantez-nous des chants de Sion ». Comment chanterions-nous le chant de l'Éternel sur une terre étrangère ? Si je t'oublie, Jérusalem, que ma droite m'oublie. Que ma langue s'attache à mon palais si je ne me souviens pas de toi, si je n'élève pas Jérusalem au sommet de ma joie. Souviens-Toi, Éternel, du jour de Jérusalem contre les fils d'Édom, qui disaient : « Rasez, rasez jusqu'à ses fondations ». Fille de Babylone, la dévastée, heureux celui qui te rendra ta rétribution. Heureux celui qui saisira et écrasera contre le rocher tes petits."""

    RU137 = """В обычные будни, когда читают Таханун, говорят:

У рек Вавилонских, там мы сидели и плакали, когда вспоминали Сион. На ивах посреди него мы повесили наши арфы. Ибо там пленители наши просили у нас слов песни, а мучители — веселья: «Спойте нам песни Сиона». Как мы будем петь песнь Г-спода на чужой земле? Если я забуду тебя, Иерусалим, да забудет правая рука моя. Да прилипнет язык мой к гортани моей, если не буду помнить о тебе, если не поставлю Иерусалим во главе радости моей. Вспомни, Г-споди, сынов Едома день Иерусалима, говоривших: «Разрушьте, разрушьте до основания». Дочь Вавилона, опустошённая, блажен, кто воздаст тебе за то, что ты нам сделала. Блажен, кто схватит и разобьёт о скалу младенцев твоих."""

    add(EN137, ES137, FR137, RU137)

    HE137 = """בימים שיש בהם תחנון (ימי חול רגילים) אומרים:

על נהרות בבל שם ישבנו גם בכינו בזכרנו את ציון. על ערבים בתוכה תלינו כנרותינו. כי שם שאלונו שובינו דברי שיר ותוללינו שמחה שירו לנו משיר ציון. איך נשיר את שיר יהוה על אדמת נכר. אם אשכחך ירושלם תשכח ימיני. תדבק לשוני לחכי אם לא אזכרכי אם לא אעלה את ירושלם על ראש שמחתי. זכר יהוה לבני אדום את יום ירושלם האמרים ערו ערו עד היסוד בה. בת בבל השדודה אשרי שישלם לך את גמולך שגמלת לנו. אשרי שיאחז ונפץ את עלליך אל הסלע."""
    T[HE137] = {"es": ES137, "fr": FR137, "ru": RU137}

    # --- Ps 126 (non-Tachanun days) ---
    EN126 = """On days when tachanun is omitted:

A song of ascents. When the Lord returned the returnees to Zion, we were like dreamers. Then our mouths will be filled with laughter and our tongues with songs of praise. Then they will say among the nations, 'The Lord has done great things for them.' The Lord has done great things for us; we were joyful. Return, O Lord, our captivity like rivulets in arid land. Those who sow with tears will reap with song. He who goes along weeping, carrying the valuable seeds, will come back with song, carrying his sheaves."""

    ES126 = """En días en que no se dice Tachanun, se recita:

Canto de ascensos. Cuando Hashem hizo volver a los cautivos de Sión, fuimos como soñadores. Entonces nuestra boca se llenó de risa y nuestra lengua de cánticos de alabanza. Entonces dirán entre las naciones: «Hashem ha hecho grandes cosas con ellos». Hashem ha hecho grandes cosas con nosotros; estábamos alegres. Vuelve, Hashem, nuestro cautiverio como arroyos en el Neguev. Los que siembran con lágrimas, con cánticos segarán. Irá y vendrá llorando, llevando la semilla; volverá con cánticos, llevando sus gavillas."""

    FR126 = """Les jours où l'on omet Tachanoun, on dit :

Cantique des degrés. Quand l'Éternel ramènera les captifs de Sion, nous serons comme des rêveurs. Alors notre bouche sera remplie de rire et notre langue de chants de louange. Alors ils diront parmi les nations : « L'Éternel a fait de grandes choses pour eux ». L'Éternel a fait de grandes choses pour nous ; nous étions dans la joie. Reviens, Éternel, notre captivité comme les torrents dans le Néguev. Ceux qui sèment avec larmes moissonneront avec chants. Il ira et viendra en pleurant, portant la semence ; il reviendra avec chants, portant ses gerbes."""

    RU126 = """В дни, когда не читают Таханун, говорят:

Песнь восхождения. Когда Г-сподь возвратил пленников Сиона, мы были как во сне. Тогда уста наши наполнились смехом и язык наш — пением. Тогда скажут между народами: «Г-сподь совершил великое для них». Г-сподь совершил великое для нас — мы радовались. Возврати, Г-споди, плен наших, как потоки в Негеве. Сеющие со слезами — с пением пожнут. Пойдёт и пойдёт, плача, неся семена; вернётся с пением, неся снопы свои."""

    add(EN126, ES126, FR126, RU126)

    HE126 = """בימים שאין בהם תחנון אומרים:

שיר המעלות בשוב יהוה את שיבת ציון היינו כחלמים. אז ימלא שחוק פינו ולשוננו רנה אז יאמרו בגוים הגדיל יהוה לעשות עם אלה. הגדיל יהוה לעשות עמנו היינו שמחים. שובה יהוה את שביתנו כאפיקים בנגב. הזרעים בדמעה ברנה יקצרו. הלוך ילך ובכה נשא משך הזרע בא יבוא ברנה נשא אלמתיו"""
    T[HE126] = {"es": ES126, "fr": FR126, "ru": RU126}

    # --- Zimmun ---
    ENZ = """Zimmun is said only when at least three Jewish men who have reached bar mitzvah (age 13 or older) ate together in the halachic sense that calls for Birkat Hamazon as one group; someone eating alone—or any gathering that does not meet this—does not recite Zimmun. When ten such men are present, include the parenthetical wording (“our God,” etc.).

My masters, let us bless!
Others respond: May the name of the Lord be blessed from now and forever.
Leader says: With the permission of our masters and teachers, let us bless (if 10: our God) He of whose food we have eaten.
Others respond: Blessed be (our God) He of whose food we have eaten and through whose goodness we live.
Leader repeats: Blessed be (our God) He of whose food we have eaten and through whose goodness we live."""

    ESZ = """El Zimmun se dice solo cuando al menos tres hombres judíos que han alcanzado la edad de bar mitzvá (13 años o más) comieron juntos de manera que exige una Birkat Hamazón común según la halajá; quien come solo — o un grupo que no cumple esto — no recita Zimmun. Cuando hay diez hombres así, se incluye la redacción entre paréntesis («nuestro Dios», etc.).

¡Maestros míos, bendigamos!
Los demás responden: Bendito sea el nombre de Hashem, ahora y para siempre.
El líder dice: Con permiso de nuestros maestros y Ravs, bendigamos (con diez: nuestro Dios) Aquel de cuya comida hemos comido.
Los demás responden: Bendito sea (nuestro Dios) Aquel de cuya comida hemos comido y por cuya bondad vivimos.
El líder repite: Bendito sea (nuestro Dios) Aquel de cuya comida hemos comido y por cuya bondad vivimos."""

    FRZ = """Le zimmoun se dit seulement lorsqu'au moins trois hommes juifs ayant atteint l'âge de la bar-mitsva (13 ans ou plus) ont mangé ensemble de manière à exiger une Birkat Hamazón commune selon la halakha ; celui qui mange seul — ou un groupe qui ne remplit pas cette condition — ne récite pas le zimmoun. Lorsque dix hommes sont présents, on inclut la formulation entre parenthèses (« notre Dieu », etc.).

Mes maîtres, bénissons !
Les autres répondent : Que le nom de l'Éternel soit béni, dès maintenant et à jamais.
Le leader dit : Avec la permission de nos maîtres et Ravs, bénissons (à dix : notre Dieu) Celui de la nourriture duquel nous avons mangé.
Les autres répondent : Béni soit (notre Dieu) Celui de la nourriture duquel nous avons mangé et par la bonté duquel nous vivons.
Le leader répète : Béni soit (notre Dieu) Celui de la nourriture duquel nous avons mangé et par la bonté duquel nous vivons."""

    RUZ = """Цимун читается только когда по крайней мере три еврейских мужчины, достигших возраста бар-мицвы (13 лет и старше), ели вместе так, что по галахе требуется общая Биркат а-Мазон; тот, кто ест один, или группа, не соответствующая этому условию, не читает цимун. Когда присутствуют десять таких мужчин, включают формулировку в скобках («Б-г наш» и т.д.).

Учителя мои, благословим!
Остальные отвечают: Да будет благословено имя Г-спода отныне и навеки.
Ведущий говорит: С дозволения наших учителей и Равов, благословим (при десяти: Б-г наш) Того, от чьей пищи мы ели.
Остальные отвечают: Благословен (Б-г наш) Тот, от чьей пищи мы ели и чьим благом мы живём.
Ведущий повторяет: Благословен (Б-г наш) Тот, от чьей пищи мы ели и чьим благом мы живём."""

    add(ENZ, ESZ, FRZ, RUZ)

    HEZ = """זימון נאמר רק כשלפחות שלושה גברים יהודיים מגיל בר־מצווה (י״ג ומעלה) אכלו יחד באופן שמחייב ברכת המזון משותפת כפי שדינה; הסועד לבד או קבוצה שלא עומדת בזה אינה אומרת זימון. כשיש עשרה גברים כאלה — משלבים את הנוסח שבסוגריים (״אלהינו״ וכו׳).

רבותי, נברך!
המסבים עונים: יהי שם יי מברך מעתה ועד עולם.
המזמן אומר: ברשות מרנן ורבנן ורבותי, נברך (בעשרה אלהינו) שאכלנו משלו.
המסבים עונים: ברוך (אלהינו) שאכלנו משלו ובטובו חיינו.
המזמן חוזר ואומר: ברוך (אלהינו) שאכלנו משלו ובטובו חיינו."""
    T[HEZ] = {"es": ESZ, "fr": FRZ, "ru": RUZ}

    # --- HaZan ---
    EN_HAZAN = "Blessed are You, Lord our God, King of the universe, who nourishes the entire world with His goodness, with grace, with kindness and with mercy. He gives bread to all flesh, for His kindness endures forever. And through His great goodness, we have never lacked, and may we never lack nourishment, for all eternity, for the sake of His great name. For He is God who nourishes and sustains all, and does good to all, and prepares food for all His creatures which He created. Blessed are You, Lord, who nourishes all."
    ES_HAZAN = "Bendito eres Tú, Hashem, Eloheinu, Rey del universo, que sustentas a todo el mundo con Tu bondad, con gracia, con bondad amorosa y con misericordia. Él da pan a toda carne, porque Su bondad amorosa es eterna. Y por Su gran bondad, nunca nos ha faltado, y no nos falte sustento jamás, por los siglos de los siglos, por amor de Su gran nombre. Porque Él es el Dios que sustenta y alimenta a todos, y hace bien a todos, y prepara alimento para todas Sus criaturas que creó. Bendito eres Tú, Hashem, que sustentas a todos."
    FR_HAZAN = "Béni sois-Tu, Éternel notre Dieu, Roi de l'univers, qui sustentes le monde entier par Ta bonté, par Ta grâce, par Ta bienveillance et par Ta miséricorde. Il donne le pain à toute chair, car Sa bienveillance est éternelle. Et par Sa grande bonté, nous n'avons jamais manqué de rien, et que nous ne manquions jamais de nourriture, à jamais, pour l'amour de Son grand nom. Car Il est le Dieu qui sustente et nourrit tous, qui fait du bien à tous, et prépare la nourriture pour toutes Ses créatures qu'Il a créées. Béni sois-Tu, Éternel, qui sustentes tous."
    RU_HAZAN = "Благословен Ты, Г-сподь, Б-г наш, Царь вселенной, Питающий весь мир Своим благом, милостью, добротой и состраданием. Он даёт хлеб всякой плоти, ибо милость Его вечна. И по великому благословению Его мы никогда не испытывали нужды, и да не будет нам недостатка в sustenance во веки веков, ради великого имени Его. Ибо Он — Б-г, Питающий и содержащий всех, Делающий добро всем и готовящий пищу для всех творений Своих, которых Он создал. Благословен Ты, Г-сподь, Питающий всех."
    add(EN_HAZAN, ES_HAZAN, FR_HAZAN, RU_HAZAN)

    HE_HAZAN = "ברוך אתה יהוה אלהינו מלך העולם הזן את העולם כלו בטובו בחן בחסד וברחמים, הוא נתן לחם לכל-בשר כי לעולם חסדו ובטובו הגדול תמיד לא חסר לנו ואל יחסר לנו מזון (תמיד) לעולם ועד בעבור שמו הגדול כי הוא אל זן ומפרנס לכל ומטיב לכל ומכין מזון לכל-בריותיו אשר ברא ברוך אתה יי הזן את הכל."
    T[HE_HAZAN] = {"es": ES_HAZAN, "fr": FR_HAZAN, "ru": RU_HAZAN.replace("sustenance", "пропитании")}

    # Fix RU_HAZAN - I had a typo with "sustenance"
    RU_HAZAN = "Благословен Ты, Г-сподь, Б-г наш, Царь вселенной, Питающий весь мир Своим благом, милостью, добротой и состраданием. Он даёт хлеб всякой плоти, ибо милость Его вечна. И по великому благословению Его мы никогда не испытывали нужды, и да не будет нам недостатка в пропитании во веки веков, ради великого имени Его. Ибо Он — Б-г, Питающий и содержащий всех, Делающий добро всем и готовящий пищу для всех творений Своих, которых Он создал. Благословен Ты, Г-сподь, Питающий всех."
